import{_ as t,c as e,o as a,a9 as r}from"./chunks/framework.UE0CKZYN.js";const x=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reference/garbage_characters.md","filePath":"reference/garbage_characters.md","lastUpdated":1775281763000}'),i={name:"reference/garbage_characters.md"},s=r('<h2 id="先说解决方案" tabindex="-1">先说解决方案 <a class="header-anchor" href="#先说解决方案" aria-label="Permalink to &quot;先说解决方案&quot;">​</a></h2><p>安装游戏时发现乱码字符立刻停止操作并转区运行安装程序进行安装.</p><p>解压时发现压缩包内有乱码字符修改代码页为日文后显示正常再进行解压缩.</p><p>解压或安装后如果出现了程序运行时提示找不到文件,大概率就是由于乱码导致的被引用的文件名发生了变动,这时候转区运行大概率无效,需要卸载后重新转区安装</p><p>部分游戏即使解压和安装时都没出错,运行时也可能出现乱码,这时候需要转区运行游戏</p><p>安装程序的转区操作和游戏的转区操作都请参考<a href="/vitepress-nav/stage1/soft/LE">转区工具使用教程</a></p><h2 id="压缩包代码页的转换" tabindex="-1">压缩包代码页的转换 <a class="header-anchor" href="#压缩包代码页的转换" aria-label="Permalink to &quot;压缩包代码页的转换&quot;">​</a></h2><p>Bandizip用户直接点击右上角的<code>代码页</code>然后选择日语之后再点击<code>解压</code></p><p>WinRAR用户点选右上角<code>选项--&gt;名称编码--&gt;日语 Shift-JIS</code>然后再点击<code>解压到</code></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>修改代码页仅在当前打开的压缩包窗口中生效,即修改完成代码页关掉窗口再右键压缩包点击解压出来的文件仍然是乱码</p></div><table><thead><tr><th>Bandizip</th><th>WinRAR</th></tr></thead><tbody><tr><td><img src="https://gcore.jsdelivr.net/gh/Rinaex/images@main/QQ20260404-132016.png" alt=""></td><td><img src="https://gcore.jsdelivr.net/gh/Rinaex/images@main/QQ20260404-132023.png" alt=""></td></tr><tr><td>转换后</td><td>转换后</td></tr><tr><td><img src="https://gcore.jsdelivr.net/gh/Rinaex/images@main/406d2dde-edad-4ed2-a96b-c6aae6a4c52d.png" alt=""></td><td><img src="https://gcore.jsdelivr.net/gh/Rinaex/images@main/04523ba1-954e-4b40-bb58-408b0b02faba.png" alt=""></td></tr></tbody></table><h2 id="乱码的形成" tabindex="-1">乱码的形成 <a class="header-anchor" href="#乱码的形成" aria-label="Permalink to &quot;乱码的形成&quot;">​</a></h2><p>乱码的成因我个人认为可以用刻舟求剑来比喻，</p><p>在计算机系统中，所有的文字符号都存储在<strong>字符集</strong>中，每个文字都有对应的<strong>码点</strong>，比如在ASCII字符集中字母A经过ASCII编码得到的值是65，那么65就是字符A在ASCII字符集中的<strong>码点</strong>。</p><p>在存储文件时,存储的是占用空间更小的<strong>码点</strong>而非文字本身，而在不同的<strong>字符集</strong>中文字的排列和码点都不相同，于是当我们使用<strong>A字符集</strong>去打开<strong>B字符集</strong>保存的文件时就会产生错乱，同样的码点对应了不同的文字甚至于根本就没有对应的字符存在</p><p>我们玩Galgame通常会遇到的是<code>Shift_JIS(日文常用编码)</code>到中文编码转换过程中出现的乱码 举个例子</p><p>日文「こんにちは」在不同编码下的表示 在Shift_JIS编码中：</p><ul><li>「こ」: 0x82 0xB1</li><li>「ん」: 0x82 0xF1</li><li>「に」: 0x82 0xBF</li><li>「ち」: 0x82 0xC1</li><li>「は」: 0x82 0xD0</li></ul><p>在GB2312编码中解释同一字节：</p><ul><li>0x82 0xB1 : 对应中文「鍙」</li><li>0x82 0xF1 : 对应中文「鐟」</li><li>0x82 0xBF : 对应中文「鐗」</li><li>0x82 0xC1 : 对应中文「鐡」</li><li>0x82 0xD0 : 对应中文「鐢」</li></ul><p>那么当我们使用中文操作系统打开使用Shift_JIS编码的「こんにちは」就会显示成「鍙鐟鐗鐡鐢」</p><p>如果上面说的你没懂，可以看看<a href="https://www.bilibili.com/video/av603967710" target="_blank" rel="noreferrer">这个视频</a>，当然不懂也完全没问题</p><p>之所以要说乱码的形成原理,是为了让大家产生一些分析能力，遇到问题时不要直接来上三板斧，虽然大概率能解决，但终究不够优雅</p>',23),o=[s];function l(n,d,c,p,g,h){return a(),e("div",null,o)}const b=t(i,[["render",l]]);export{x as __pageData,b as default};
